/// Look up the substitution score for two residue characters.
#[inline]
pub fn blosum_score(a: u8, b: u8) -> i32 {
    BLOSUM[a as usize][b as usize]
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_blosum62_diagonal() {
        // A-A match score in BLOSUM62 is 4
        assert_eq!(blosum_score(b'A', b'A'), 4);
        // W-W match score is 11
        assert_eq!(blosum_score(b'W', b'W'), 11);
    }

    #[test]
    fn test_blastn_match_mismatch() {
        // RNA match = 2, mismatch = -3
        assert_eq!(blosum_score(b'a', b'a'), 2);
        assert_eq!(blosum_score(b'a', b'c'), -3);
        // t vs u matching = 2
        assert_eq!(blosum_score(b't', b'u'), 2);
    }

    #[test]
    fn test_zero_for_unknown() {
        assert_eq!(blosum_score(b'?', b'?'), 0);
        assert_eq!(blosum_score(0, 0), 0);
    }
}
